2304→            }
2305→            if (url.startsWith("tts-voices:")) {
2306→                showDialogFragment(TtsVoicesDialogFragment())
2307→                return true
2308→            }
2309→            if (url.startsWith("file") || url.startsWith("data:")) {
2310→                return false // Let the webview load files, i.e. local images.
2311→            }
2312→            if (url.startsWith("typeblurtext:")) {
2313→                // Store the text the javascript has send us…
2314→                typeAnswer!!.input = decodeUrl(url.replaceFirst("typeblurtext:".toRegex(), ""))
2315→                return true
2316→            }
2317→            if (url.startsWith("typeentertext:")) {
2318→                // Store the text the javascript has send us…
2319→                typeAnswer!!.input = decodeUrl(url.replaceFirst("typeentertext:".toRegex(), ""))
2320→                // … and show the answer.
2321→                flipCardLayout!!.performClick()
2322→                return true
2323→            }
2324→
2325→            // card.html reload
2326→            if (url.startsWith("signal:reload_card_html")) {
2327→                redrawCard()
2328→                return true
2329→            }
2330→
2331→            when (val signalOrdinal = WebViewSignalParserUtils.getSignalFromUrl(url)) {
2332→                WebViewSignalParserUtils.SIGNAL_UNHANDLED -> {}
2333→                WebViewSignalParserUtils.SIGNAL_NOOP -> return true
2334→                WebViewSignalParserUtils.TYPE_FOCUS -> return true
2335→
2336→                WebViewSignalParserUtils.RELINQUISH_FOCUS -> {
2337→                    // #5811 - The WebView could be focused via mouse. Allow components to return focus to Android.
2338→                    focusAnswerCompletionField()
2339→                    return true
2340→                }
2341→
2342→                WebViewSignalParserUtils.SHOW_ANSWER -> {
2343→                    // display answer when showAnswer() called from card.js
2344→                    if (!Companion.displayAnswer) {
2345→                        displayCardAnswer()
2346→                    }
2347→                    return true
2348→                }
2349→
2350→                WebViewSignalParserUtils.ANSWER_ORDINAL_1 -> {
2351→                    flipOrAnswerCard(EASE_1)
2352→                    return true
2353→                }
2354→
2355→                WebViewSignalParserUtils.ANSWER_ORDINAL_2 -> {
2356→                    flipOrAnswerCard(EASE_2)
2357→                    return true
2358→                }
2359→
2360→                WebViewSignalParserUtils.ANSWER_ORDINAL_3 -> {
2361→                    flipOrAnswerCard(EASE_3)
2362→                    return true
2363→                }
2364→
2365→                WebViewSignalParserUtils.ANSWER_ORDINAL_4 -> {
2366→                    flipOrAnswerCard(EASE_4)
2367→                    return true
2368→                }
2369→
2370→                else -> {
2371→                    // We know it was a signal, but forgot a case in the case statement.
2372→                    // This is not the same as SIGNAL_UNHANDLED, where it isn't a known signal.
2373→                    Timber.w("Unhandled signal case: %d", signalOrdinal)
2374→                    return true
2375→                }
2376→            }
2377→            var intent: Intent? = null
2378→            try {
2379→                if (url.startsWith("intent:")) {
2380→                    intent = Intent.parseUri(url, Intent.URI_INTENT_SCHEME)
2381→                } else if (url.startsWith("android-app:")) {
2382→                    intent = Intent.parseUri(url, Intent.URI_ANDROID_APP_SCHEME)
2383→                }
2384→                if (intent != null) {
2385→                    if (packageManager.resolveActivityCompat(
2386→                            intent,
2387→                            ResolveInfoFlagsCompat.EMPTY
2388→                        ) == null
2389→                    ) {
2390→                        val packageName = intent.getPackage()
2391→                        if (packageName == null) {
2392→                            Timber.d(
2393→                                "Not using resolved intent uri because not available: %s",
2394→                                intent
2395→                            )
2396→                            intent = null
2397→                        } else {
2398→                            Timber.d(
2399→                                "Resolving intent uri to market uri because not available: %s",
2400→                                intent
2401→                            )
2402→                            intent = Intent(
2403→                                Intent.ACTION_VIEW,
2404→                                Uri.parse("market://details?id=$packageName")
2405→                            )
2406→                            if (packageManager.resolveActivityCompat(
2407→                                    intent,
2408→                                    ResolveInfoFlagsCompat.EMPTY
2409→                                ) == null
2410→                            ) {
2411→                                intent = null
2412→                            }
2413→                        }
2414→                    } else {
