2416→                        intent.addCategory(Intent.CATEGORY_BROWSABLE)
2417→                    }
2418→                }
2419→            } catch (t: Throwable) {
2420→                Timber.w("Unable to parse intent uri: %s because: %s", url, t.message)
2421→            }
2422→            if (intent == null) {
2423→                Timber.d("Opening external link \"%s\" with an Intent", url)
2424→                intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
2425→            } else {
2426→                Timber.d("Opening resolved external link \"%s\" with an Intent: %s", url, intent)
2427→            }
2428→            try {
2429→                startActivity(intent)
2430→            } catch (e: ActivityNotFoundException) {
2431→                Timber.w(e) // Don't crash if the intent is not handled
2432→            }
2433→            return true
2434→        }
