","new_string":"    @VisibleForTesting(otherwise = VisibleForTesting.PROTECTED)
    open fun displayCardAnswer() {
        // When using the in-card input tag (Advanced → Type answer into the card), the typed text lives inside the
        // WebView and may not be sent to Android until blur/enter.
        // If the user flips the card without blurring (e.g. tapping "Show Answer"), capture the current value first.
        if (typeAnswerValueFetchInProgress) {
            return
        }
        if (shouldFetchTypeAnswerFromWebViewBeforeFlipping()) {
            fetchTypeAnswerFromWebView { typed ->
                runOnUiThread {
                    typeAnswer?.input = typed
                    displayCardAnswerInternal()
                }
            }
            return
        }

        displayCardAnswerInternal()
    }

    private var typeAnswerValueFetchInProgress: Boolean = false

    private fun shouldFetchTypeAnswerFromWebViewBeforeFlipping(): Boolean {
        val ta = typeAnswer ?: return false
        return ta.useInputTag && !displayAnswer
    }

    private fun fetchTypeAnswerFromWebView(onResult: (String) -> Unit) {
        typeAnswerValueFetchInProgress = true
        val cardIdAtRequestTime = currentCard?.id
        processCardAction { cardWebView: WebView? ->
            if (cardWebView == null) {
                typeAnswerValueFetchInProgress = false
                onResult("")
                return@processCardAction
            }
            cardWebView.evaluateJavascript(
                "(function(){var el=document.getElementById('typeans'); return el ? el.value : '';})()"
            ) { result: String? ->
                typeAnswerValueFetchInProgress = false
                // Card may have changed while we were waiting (or the user may have already flipped)
                if (cardIdAtRequestTime != currentCard?.id || displayAnswer) {
                    return@evaluateJavascript
                }
                onResult(parseJavascriptStringResult(result))
            }
        }
    }

    private fun parseJavascriptStringResult(result: String?): String {
        if (result.isNullOrEmpty() || result == "null" || result == "undefined") {
            return ""
        }
        return try {
            (org.json.JSONTokener(result).nextValue() as? String) ?: ""
        } catch (t: Throwable) {
            Timber.w(t, "Unable to parse JS result: %s", result)
            ""
        }
    }

    private fun displayCardAnswerInternal() {
        // #7294 Required in case the animation end action does not fire:
        actualHideEaseButtons()
        Timber.d("displayCardAnswer()")
        mediaErrorHandler.onCardSideChange()
        backButtonPressedToReturn = false

        // prevent answering (by e.g. gestures) before card is loaded
        if (currentCard == null) {
            return
        }

        // TODO needs testing: changing a card's model without flipping it back to the front
        //  (such as editing a card, then editing the card template)
        typeAnswer!!.updateInfo(getColUnsafe, currentCard!!, resources)

        // Explicitly hide the soft keyboard. It *should* be hiding itself automatically,
        // but sometimes failed to do so (e.g. if an OnKeyListener is attached).
        if (typeAnswer!!.validForEditText()) {
            val inputMethodManager = getSystemService(INPUT_METHOD_SERVICE) as InputMethodManager
            inputMethodManager.hideSoftInputFromWindow(answerField!!.windowToken, 0)
        }
        displayAnswer = true
        answerField!!.visibility = View.GONE
        // Clean up the user answer and the correct answer
        if (!typeAnswer!!.useInputTag) {
            typeAnswer!!.input = answerField!!.text.toString()
        }
        isSelecting = false
        val answerContent = htmlGenerator!!.generateHtml(getColUnsafe, currentCard!!, SingleCardSide.BACK)
        automaticAnswer.onDisplayAnswer()
        launchCatchingTask {
            if (!automaticAnswerShouldWaitForAudio()) {
                automaticAnswer.scheduleAutomaticDisplayQuestion()
            }
        }
        updateCard(answerContent)
        displayAnswerBottomBar()
    }
